            Tags = """["admin","automations","leads","assignment","reference"]""",
            ContentJson = """{"title":"Assignment Rules Field Reference","groups":[{"heading":"List Columns","items":[{"label":"Priority","value":"The order number that decides when the rule is checked. Lower numbers are checked first, and the first active rule that fits a lead wins. Click to sort."},{"label":"Name","value":"The rule's label. Click to sort."},{"label":"Type","value":"Round Robin, Territory, Industry, or Account-Based. Click to sort."},{"label":"Active","value":"Shows whether the rule is on or paused. Paused rules are skipped. Click to sort."},{"label":"Created","value":"When the rule was created. Click to sort."},{"label":"Actions","value":"Edit (pencil) and Delete (trash) buttons on each row. Clicking the row also opens Edit."}]},{"heading":"Rule Window — Common Fields","items":[{"label":"Name (required)","value":"A label for the rule, up to 100 characters. Shown in the list."},{"label":"Type (required)","value":"Round Robin, Territory, Industry, or Account-Based. Changing it swaps the fields shown below."},{"label":"Priority (required)","value":"The order number that decides when the rule is checked; lower is checked first. Starts at 100 for a new rule."},{"label":"Active (edit only)","value":"An on/off switch, shown only when editing an existing rule. Off pauses the rule without deleting it. New rules start active."}]},{"heading":"Round Robin — Fields","items":[{"label":"Reps","value":"The reps to rotate through. Each new matching lead goes to the next rep in turn."}]},{"heading":"Territory — Fields","items":[{"label":"States","value":"The states the region covers. Two-letter codes are stored in capitals for you (ca becomes CA)."},{"label":"ZIP Codes","value":"The ZIP codes the region covers. You can set states, ZIP codes, or both to define the region."}]},{"heading":"Industry — Fields","items":[{"label":"Industries","value":"The industries the rule covers. A lead in one of these industries is handled by this rule."}]},{"heading":"Account-Based — Fields","items":[{"label":"(none)","value":"Account-Based rules need no extra fields — a note in the window explains the lead goes to whoever already owns the company it belongs to."}]},{"heading":"Advanced","items":[{"label":"Advanced (collapsible)","value":"A backup option under a collapsible Advanced section, for rare cases the standard form doesn't cover yet. Used only when the regular fields are left empty — otherwise those fields take priority."}]},{"heading":"How It Behaves","items":[{"label":"First active match wins","value":"Rules are checked from the lowest priority number up; the first active rule that fits decides the owner. Paused rules are skipped."},{"label":"Name required","value":"You can't save until you enter a name (up to 100 characters)."},{"label":"Type required","value":"You can't save until you pick a type."},{"label":"Priority required","value":"You can't save until you enter a priority number."},{"label":"States go to capitals","value":"Two-letter state codes are stored in capitals when you save."},{"label":"Active by default","value":"A new rule is active right away. Use the Active switch while editing to pause it later."}]},{"heading":"Who Can Use It","items":[{"label":"View / Create / Edit","value":"Admin or Manager role."},{"label":"Delete","value":"Admin role only."}]}]}"""
        });

        // ── Assignment Rules Walkthrough ─────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assignment Rules — Guided Tour",
            Slug = "assignment-rules-walkthrough",
            Summary = "A guided tour of the Assignment Rules admin page: the rules table, priority ordering, the New Rule action, and the per-row edit/delete controls.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["admin","automations","leads","assignment","walkthrough"]""",
            ContentJson = """{"appRoute":"/admin/assignment-rules","startButtonLabel":"Tour Assignment Rules","steps":[{"element":".toolbar__hint","popover":{"title":"Lead Assignment Rules","description":"This page holds the rules that send new leads to reps automatically. Rules run in priority order, and the first active rule that fits a lead picks its owner.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"The Rules List","description":"Each row is one rule, showing its priority (lower numbers are checked first), name, type, whether it's active, and when it was created. Click the Priority heading to sort and see the order your leads fall through.","side":"top"}},{"element":"[data-testid='assignment-rule-new-btn']","popover":{"title":"New Rule","description":"Click here to add a rule. The window asks for a name, a type, and a priority, then shows the fields that type needs — the reps to rotate through, the states or ZIP codes to cover, or the industries to match. New rules are active right away.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Edit, Pause, or Delete","description":"Click the pencil on a row (or the row itself) to reopen it — while editing, an Active switch lets you pause a rule without deleting it. The trash icon deletes a rule after you confirm. Give a rule a lower priority number to make it win over broader rules below it.","side":"top"}}]}"""
        });

        // ── Assignment Rules Knowledge Check (Quiz) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assignment Rules Knowledge Check",
            Slug = "assignment-rules-quiz",
            Summary = "Test your understanding of lead assignment rules: priority order, the four rule types, the fields each type needs, and pausing vs deleting.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["admin","automations","leads","assignment","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":6,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ar1","text":"You have several active assignment rules. Which one decides where a new lead goes?","options":[{"id":"a","text":"The first active rule that fits the lead, checked from the lowest priority number up","isCorrect":true},{"id":"b","text":"The rule with the highest priority number"},{"id":"c","text":"All matching rules apply, and the lead is split among their reps"},{"id":"d","text":"The most recently created rule"}],"explanation":"Rules are checked from the lowest priority number up. The first active rule that fits the lead wins and picks the owner. Paused rules are skipped, and once a rule fits, the checking stops."},{"id":"ar2","text":"Which rule type spreads incoming leads evenly across a group of reps?","options":[{"id":"a","text":"Round Robin","isCorrect":true},{"id":"b","text":"Territory"},{"id":"c","text":"Industry"},{"id":"d","text":"Account-Based"}],"explanation":"Round Robin lists a group of reps and gives each new matching lead to the next rep in turn, spreading leads evenly. Territory matches by location, Industry by field of work, and Account-Based by the company the lead belongs to."},{"id":"ar3","text":"You want reps to own regions so a lead in California always goes to the West-coast rep. Which type and fields do you use?","options":[{"id":"a","text":"Territory, listing the states and/or ZIP codes it covers","isCorrect":true},{"id":"b","text":"Round Robin, listing every rep"},{"id":"c","text":"Industry, listing California as an industry"},{"id":"d","text":"Account-Based, with no extra fields"}],"explanation":"Territory rules match leads by location. You list the states (such as CA) and/or ZIP codes the region covers, and a lead with an address in that area goes to the rule's owner. State codes are stored in capitals for you."},{"id":"ar4","text":"You want to stop using a rule for now but keep it for later. What's the best action?","options":[{"id":"a","text":"Edit the rule and turn off its Active switch","isCorrect":true},{"id":"b","text":"Delete the rule and re-create it later"},{"id":"c","text":"Set its priority to 0"},{"id":"d","text":"Clear all of its fields"}],"explanation":"Editing a rule shows an Active switch. Turning it off pauses the rule — it's skipped but kept, so you can turn it back on later. Deleting removes the rule for good."},{"id":"ar5","text":"You create a new Account-Based rule. Why doesn't the window ask for states, reps, or industries?","options":[{"id":"a","text":"Account-Based sends a lead to whoever already owns the company it belongs to, so no extra fields are needed","isCorrect":true},{"id":"b","text":"Account-Based rules can't be set up and only run overnight"},{"id":"c","text":"You must enter those fields in the Advanced section instead"},{"id":"d","text":"Account-Based is a placeholder type that does nothing"}],"explanation":"Account-Based rules use the company link to send a lead to the rep who already owns that company, keeping all of a company's contacts with one rep. Because the company link drives the assignment, the window shows a note instead of extra fields."},{"id":"ar6","text":"Two rules could fit the same lead: a broad catch-all and a specific key-account rule. How do you make the specific rule win?","options":[{"id":"a","text":"Give the specific rule a lower priority number than the catch-all so it's checked first","isCorrect":true},{"id":"b","text":"Give the specific rule a higher priority number than the catch-all"},{"id":"c","text":"Mark the catch-all as paused permanently"},{"id":"d","text":"Delete the catch-all rule"}],"explanation":"Because the first active match wins and rules are checked from the lowest priority number up, giving the specific rule a lower number means it's checked before the broad catch-all. The specific rule fits first, so it picks the owner and the catch-all is never reached for that lead."}]}"""
        });

        // ── Auto-PO Admin Settings (Article) ─────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Auto-PO Settings (Admin)",
            Slug = "auto-po-admin-overview",
            Summary = "The Admin → Auto-PO settings panel: enabling automatic purchasing, choosing Suggest/Draft/Automatic mode, the buffer days, chat notifications, and the nightly demand review.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/admin/auto-po"]""",
            Tags = """["admin","automations","auto-po","purchasing","procurement"]""",
            ContentJson = """{"body":"## Auto-PO Settings (Admin)\n\nAuto-PO watches demand for the parts you buy and proposes (or creates) purchase orders to cover it, so a buyer doesn't have to catch every shortage by hand. This admin page — Admin → Auto-PO — is where you turn it on and decide how far it goes on its own. The suggestions it makes are reviewed on the **Suggestions** tab of the Purchase Orders page; this page is just the settings.\n\n### How Auto-PO works at a glance\n\nEach night, Auto-PO reviews demand for the parts you buy (from sales orders and other needs), compares it against stock on hand and orders already on the way, and where it sees a shortage coming it makes a suggestion for that part's preferred vendor. What happens to the suggestion next depends on the **mode** you pick below. If you don't want to wait for the nightly run, you can start a review yourself from the Suggestions tab with the Run Analysis button.\n\n### The settings\n\n**Enable Auto-PO** — the main switch. When it's off, no suggestions are made and the nightly review does nothing. Turn it on to start.\n\n**Mode** — controls how far Auto-PO goes on its own:\n- **Suggest** — Auto-PO only makes suggestions. A buyer reviews them on the Suggestions tab and decides which to turn into purchase orders. This is the most cautious setting and the usual starting point.\n- **Draft** — Auto-PO goes a step further and creates **draft** purchase orders from the suggestions, ready for a buyer to review and send. Nothing goes to a vendor on its own; a person still clicks Submit.\n- **Automatic** — Auto-PO creates and sends the purchase orders without anyone reviewing them. Use this only once you trust your demand numbers and vendor details, since no person checks the order first.\n\n**Buffer Days** — a safety cushion. Auto-PO acts as if each part is needed this many days earlier, so orders go out with some room to spare. A bigger buffer orders sooner (safer, more stock on hand); a smaller buffer orders later (leaner, less room for delays).\n\n**Notify Chat** — when on, Auto-PO posts in chat whenever it makes suggestions or orders, so the purchasing team hears about it without watching the Suggestions tab. Turn it off to keep it quiet.\n\nClick **Save** to keep your settings. They apply on the next review, whether that's the nightly run or one you start yourself.\n\n### Choosing a mode in practice\n\nMost teams start in **Suggest** to build trust — you can see what Auto-PO *would* order before letting it act. As your part and vendor details prove reliable, teams move to **Draft** so the busywork of opening orders is done for them while a buyer still approves each one. **Automatic** is for steady, well-understood restocking where ordering without review is genuinely safe.\n\n### Where the suggestions go\n\nThis page never lists suggestions — it only holds the settings. To review, accept, dismiss, or accept several suggestions at once, go to **Purchase Orders → Suggestions**. See the related Auto-PO suggestions training for that.\n\n### Who can use it\n\nThese settings are for Admins. Reviewing and accepting suggestions is open to Admins, Managers, and Office Managers.","sections":[]}"""
        });

        // ── Automations Advanced Reference (Reference) ───────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assignment Rules & Auto-PO — Advanced Guide",
            Slug = "automations-reference",
            Summary = "A deeper guide for admins: the Advanced backup option on a rule, the details that matter when saving a rule, who can do what, and exactly what Auto-PO's nightly review looks at.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["automations","reference","advanced"]""",
            ContentJson = """{"body":"## The Advanced Option on a Rule\n\nWhen you set up an assignment rule, you fill in the fields for its type — the reps for Round Robin, the states or ZIP codes for Territory, the industries for Industry. Account-Based needs no extra fields, since the company link does the work.\n\nEach rule window also has a collapsible **Advanced** section. Most admins never open it. It's a backup for rare cases the standard form doesn't cover yet. The rule is worth knowing: whenever the regular fields are filled in, they always take priority, and the Advanced section is only used when those fields are left empty.\n\n## Rule Details & State Capitals\n\nA few small things to keep in mind when saving a rule:\n\n- **Name** — required. You can't save a rule without one.\n- **Priority** — a whole number. Lower numbers are checked first, and if two rules share a number, they're checked in name order.\n- **Type fields** — saved as you enter them.\n- **Active** — a new rule starts active; the Active switch appears only when editing.\n\n**State capitals** — when you type state codes for a Territory rule, they're stored in capitals for you (ca becomes CA). ZIP codes are left as you type them.\n\nEvery change you make to a rule — creating it, editing it, or deleting it — is tracked, so you can look back and see who changed what and when. Deleting a rule takes it out of the list but doesn't wipe that history.\n\n## Who Can Do What\n\n**Assignment Rules:**\n\n- Viewing, creating, and updating rules is for Admins and Managers.\n- Deleting a rule is Admin-only.\n\n**Auto-PO:**\n\n- Reviewing suggestions — accepting, dismissing, or accepting several at once — is open to Admins, Managers, and Office Managers.\n- Changing the settings and starting a review yourself are Admin-only. Managers and Office Managers can act on suggestions but can't change the settings.\n\n## Auto-PO Settings & What the Nightly Review Looks At\n\nAuto-PO has four settings:\n\n- **Enable Auto-PO** — the main on/off switch (off by default).\n- **Mode** — Suggest, Draft, or Automatic.\n- **Buffer Days** — a safety cushion, from 0 to 30 days.\n- **Notify Chat** — whether Auto-PO posts in chat when it acts.\n\nThe nightly review runs once a day, in the early morning. It's not something you schedule — it's simply built in.\n\n**What the nightly review counts as demand and supply:**\n\n- **Demand** is what your open sales orders still need — the work that's been ordered and confirmed but hasn't fully shipped yet. Anything already shipped is done, so it doesn't count.\n- **Supply already on the way** is what you've already ordered from vendors but haven't fully received yet, so Auto-PO doesn't order the same thing twice.\n\nAuto-PO works out what you'll be short by comparing that demand against stock on hand, orders on the way, and your safety-stock level. Parts you've marked to leave out are skipped. Then, for each vendor: in **Suggest** mode it makes one suggestion per part (and won't repeat a suggestion that's already waiting for review); in **Draft** or **Automatic** mode it groups the parts needed within the next week into orders — Automatic sends them, Draft leaves them for a buyer to send. A vendor can have its own mode that overrides the overall setting. Each order notes which sales orders drove the need, so a buyer can see why it was raised. Admins, Managers, and Office Managers are notified, and review happens on Purchase Orders → Suggestions, not on this settings page.","sections":[]}"""
        });

        Log.Information("Seeded Automations training modules");
    }
}
